(function () {
  window.DENO_DOC_SEARCH_INDEX = {"kind":"search","nodes":[{"id":"namespace_bkgdchunk","kind":[{"char":"I","kind":"Interface","title":"Interface"}],"name":"BkgdChunk","file":".","doc":"PNG bKGD (background color) chunk structure.The bKGD chunk specifies a default background color for displaying PNG images. The interpretation of the data depends on the image's color type (from IHDR chunk):Color type 0, 4 (Grayscale): 2 bytes representing a gray level value (u16be). This value should be used as the background when displaying the image.Color type 2, 6 (RGB): 6 bytes representing RGB values (3x u16be). These values specify the background red, green, and blue components.Color type 3 (Indexed): 1 byte representing a palette index (u8). This index references an entry in the PLTE chunk to use as background.The bKGD chunk must appear before the first IDAT chunk. For indexed color (type 3), it must also appear after the PLTE chunk.","url":"././~/BkgdChunk.html","deprecated":false},{"id":"namespace_bkgdchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BkgdChunk.type","file":".","doc":"Chunk type identifier, always \"bKGD\"","url":"././~/BkgdChunk.type.html","deprecated":false},{"id":"namespace_bkgdchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BkgdChunk.data","file":".","doc":"Background color data","url":"././~/BkgdChunk.data.html","deprecated":false},{"id":"namespace_bkgdchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BkgdChunk.data.values","file":".","doc":"Raw background color values as bytes.Interpretation depends on the image's color type:Color type 0, 4: 2 bytes (u16be gray level)Color type 2, 6: 6 bytes (3x u16be RGB values)Color type 3: 1 byte (u8 palette index)","url":"././~/BkgdChunk.data.values.html","deprecated":false},{"id":"namespace_idatchunk","kind":[{"char":"I","kind":"Interface","title":"Interface"}],"name":"IdatChunk","file":".","doc":"Refined IDAT (Image Data) chunk structure.The IDAT chunk contains the compressed image data. Multiple IDAT chunks can appear in a PNG file, and their data should be concatenated before decompression.","url":"././~/IdatChunk.html","deprecated":false},{"id":"namespace_idatchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IdatChunk.type","file":".","doc":"Chunk type identifier, always \"IDAT\"","url":"././~/IdatChunk.type.html","deprecated":false},{"id":"namespace_idatchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IdatChunk.data","file":".","doc":"Decompressed zlib data structure","url":"././~/IdatChunk.data.html","deprecated":false},{"id":"namespace_iendchunk","kind":[{"char":"I","kind":"Interface","title":"Interface"}],"name":"IendChunk","file":".","doc":"Refined IEND (Image End) chunk structure.The IEND chunk marks the end of the PNG datastream. It has no data field and must be the last chunk in the file.","url":"././~/IendChunk.html","deprecated":false},{"id":"namespace_iendchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IendChunk.type","file":".","doc":"Chunk type identifier, always \"IEND\"","url":"././~/IendChunk.type.html","deprecated":false},{"id":"namespace_iendchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IendChunk.crc","file":".","doc":"CRC checksum (always the same for IEND since data is empty)","url":"././~/IendChunk.crc.html","deprecated":false},{"id":"namespace_ihdrchunk","kind":[{"char":"I","kind":"Interface","title":"Interface"}],"name":"IhdrChunk","file":".","doc":"Refined IHDR (Image Header) chunk structure.The IHDR chunk is the first chunk in a PNG file and contains critical image metadata including dimensions, bit depth, color type, and compression settings.","url":"././~/IhdrChunk.html","deprecated":false},{"id":"namespace_ihdrchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IhdrChunk.type","file":".","doc":"Chunk type identifier, always \"IHDR\"","url":"././~/IhdrChunk.type.html","deprecated":false},{"id":"namespace_ihdrchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IhdrChunk.data","file":".","doc":"Parsed image header data","url":"././~/IhdrChunk.data.html","deprecated":false},{"id":"namespace_ihdrchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IhdrChunk.data.width","file":".","doc":"Image width in pixels (1 to 2^31-1)","url":"././~/IhdrChunk.data.width.html","deprecated":false},{"id":"namespace_ihdrchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IhdrChunk.data.height","file":".","doc":"Image height in pixels (1 to 2^31-1)","url":"././~/IhdrChunk.data.height.html","deprecated":false},{"id":"namespace_ihdrchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IhdrChunk.data.bitDepth","file":".","doc":"Bit depth: 1, 2, 4, 8, or 16 depending on color type","url":"././~/IhdrChunk.data.bitDepth.html","deprecated":false},{"id":"namespace_ihdrchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IhdrChunk.data.colorType","file":".","doc":"Color type: 0=grayscale, 2=RGB, 3=indexed, 4=grayscale+alpha, 6=RGBA","url":"././~/IhdrChunk.data.colorType.html","deprecated":false},{"id":"namespace_ihdrchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IhdrChunk.data.compressionMethod","file":".","doc":"Compression method, always 0 (deflate)","url":"././~/IhdrChunk.data.compressionMethod.html","deprecated":false},{"id":"namespace_ihdrchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IhdrChunk.data.filterMethod","file":".","doc":"Filter method, always 0 (adaptive filtering)","url":"././~/IhdrChunk.data.filterMethod.html","deprecated":false},{"id":"namespace_ihdrchunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"IhdrChunk.data.interlaceMethod","file":".","doc":"Interlace method: 0=none, 1=Adam7","url":"././~/IhdrChunk.data.interlaceMethod.html","deprecated":false},{"id":"namespace_pltechunk","kind":[{"char":"I","kind":"Interface","title":"Interface"}],"name":"PlteChunk","file":".","doc":"Refined PLTE (Palette) chunk structure.The PLTE chunk contains the color palette for indexed-color PNG images (color type 3). Each palette entry is an RGB triplet.","url":"././~/PlteChunk.html","deprecated":false},{"id":"namespace_pltechunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PlteChunk.type","file":".","doc":"Chunk type identifier, always \"PLTE\"","url":"././~/PlteChunk.type.html","deprecated":false},{"id":"namespace_pltechunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PlteChunk.data","file":".","doc":"Parsed palette data","url":"././~/PlteChunk.data.html","deprecated":false},{"id":"namespace_pltechunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PlteChunk.data.colors","file":".","doc":"Array of RGB color triplets (0-255 for each component)","url":"././~/PlteChunk.data.colors.html","deprecated":false},{"id":"namespace_trnschunk","kind":[{"char":"I","kind":"Interface","title":"Interface"}],"name":"TrnsChunk","file":".","doc":"PNG tRNS (transparency) chunk structure.The tRNS chunk specifies transparency information for images without a full alpha channel. The interpretation of the data depends on the image's color type (from IHDR chunk):Color type 0 (Grayscale): 2 bytes representing a single gray level value (u16be). Pixels matching this gray level are fully transparent, all others are opaque.Color type 2 (RGB): 6 bytes representing RGB values (3x u16be). Pixels matching this RGB color are fully transparent, all others are opaque.Color type 3 (Indexed): N bytes (1-256) representing alpha values for palette entries. Each byte is a u8 alpha value: 0 = fully transparent, 255 = fully opaque. Missing entries default to fully opaque.The tRNS chunk must appear after PLTE (if present) and before the first IDAT chunk. It is prohibited for color types 4 and 6, which already have full alpha channels.","url":"././~/TrnsChunk.html","deprecated":false},{"id":"namespace_trnschunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"TrnsChunk.type","file":".","doc":"Chunk type identifier, always \"tRNS\"","url":"././~/TrnsChunk.type.html","deprecated":false},{"id":"namespace_trnschunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"TrnsChunk.data","file":".","doc":"Transparency data","url":"././~/TrnsChunk.data.html","deprecated":false},{"id":"namespace_trnschunk","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"TrnsChunk.data.values","file":".","doc":"Raw transparency values as bytes.Interpretation depends on the image's color type:Color type 0: 2 bytes (u16be gray level)Color type 2: 6 bytes (3x u16be RGB values)Color type 3: 1-256 bytes (u8 alpha values for palette entries)","url":"././~/TrnsChunk.data.values.html","deprecated":false},{"id":"namespace_bkgdchunkrefiner","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"bkgdChunkRefiner","file":".","doc":"Creates a refiner for bKGD (background color) chunks.Converts between raw binary bKGD chunks and structured BkgdChunk representations. The refiner handles all three background color formats (grayscale, RGB, indexed) by storing raw byte values that can be interpreted based on the image's color type.","url":"././~/bkgdChunkRefiner.html","deprecated":false},{"id":"namespace_idatchunkrefiner","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"idatChunkRefiner","file":".","doc":"Creates a refiner for IDAT (Image Data) chunks.This refiner transforms raw IDAT chunk bytes into a structured IdatChunk object with decompressed image data.","url":"././~/idatChunkRefiner.html","deprecated":false},{"id":"namespace_iendchunkrefiner","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"iendChunkRefiner","file":".","doc":"Creates a refiner for IEND (Image End) chunks.This refiner transforms raw IEND chunk bytes into a structured IendChunk object. Since IEND has no data, this simply converts the type field.","url":"././~/iendChunkRefiner.html","deprecated":false},{"id":"namespace_ihdrchunkrefiner","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"ihdrChunkRefiner","file":".","doc":"Creates a refiner for IHDR (Image Header) chunks.This refiner transforms raw IHDR chunk bytes into a structured IhdrChunk object with parsed image metadata fields.","url":"././~/ihdrChunkRefiner.html","deprecated":false},{"id":"namespace_pltechunkrefiner","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"plteChunkRefiner","file":".","doc":"Creates a refiner for PLTE (Palette) chunks.This refiner transforms raw PLTE chunk bytes into a structured PlteChunk object with parsed RGB color triplets.","url":"././~/plteChunkRefiner.html","deprecated":false},{"id":"namespace_trnschunkrefiner","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"trnsChunkRefiner","file":".","doc":"Creates a refiner for tRNS (transparency) chunks.Converts between raw binary tRNS chunks and structured TrnsChunk representations. The refiner handles all three transparency formats (grayscale, RGB, indexed) by storing raw byte values that can be interpreted based on the image's color type.","url":"././~/trnsChunkRefiner.html","deprecated":false},{"id":"namespace_pngfile","kind":[{"char":"I","kind":"Interface","title":"Interface"}],"name":"PngFile","file":".","doc":"PNG file structure containing signature and chunks.A PNG file consists of an 8-byte signature followed by a series of chunks. The signature is always the same: { highBitByte: 137, signature: \"PNG\", dosEOF: \"\\u001a\", dosLineEnding: \"\\r\\n\", unixLineEnding: \"\\n\" }.","url":"././~/PngFile.html","deprecated":false},{"id":"namespace_pngfile","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PngFile.signature","file":".","doc":"The 8-byte PNG signature: [137, 80, 78, 71, 13, 10, 26, 10]","url":"././~/PngFile.signature.html","deprecated":false},{"id":"namespace_pngfile","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PngFile.signature.highBitByte","file":".","doc":"","url":"././~/PngFile.signature.highBitByte.html","deprecated":false},{"id":"namespace_pngfile","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PngFile.signature.signature","file":".","doc":"","url":"././~/PngFile.signature.signature.html","deprecated":false},{"id":"namespace_pngfile","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PngFile.signature.dosLineEnding","file":".","doc":"","url":"././~/PngFile.signature.dosLineEnding.html","deprecated":false},{"id":"namespace_pngfile","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PngFile.signature.dosEOF","file":".","doc":"","url":"././~/PngFile.signature.dosEOF.html","deprecated":false},{"id":"namespace_pngfile","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PngFile.signature.unixLineEnding","file":".","doc":"","url":"././~/PngFile.signature.unixLineEnding.html","deprecated":false},{"id":"namespace_pngfile","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PngFile.chunks","file":".","doc":"Array of PNG chunks in the file","url":"././~/PngFile.chunks.html","deprecated":false},{"id":"namespace_pngchunkunknown","kind":[{"char":"I","kind":"Interface","title":"Interface"}],"name":"PngChunkUnknown","file":".","doc":"Generic PNG chunk structure.Each PNG chunk consists of a 4-byte length field, 4-byte type field, variable-length data, and 4-byte CRC checksum. The length field specifies the number of bytes in the data field.","url":"././~/PngChunkUnknown.html","deprecated":false},{"id":"namespace_pngchunkunknown","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PngChunkUnknown.length","file":".","doc":"Length of the data field in bytes (4-byte big-endian)","url":"././~/PngChunkUnknown.length.html","deprecated":false},{"id":"namespace_pngchunkunknown","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PngChunkUnknown.type","file":".","doc":"Type (4 bytes)","url":"././~/PngChunkUnknown.type.html","deprecated":false},{"id":"namespace_pngchunkunknown","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PngChunkUnknown.data","file":".","doc":"Data (variable length)","url":"././~/PngChunkUnknown.data.html","deprecated":false},{"id":"namespace_pngchunkunknown","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"PngChunkUnknown.crc","file":".","doc":"CRC (4 bytes)","url":"././~/PngChunkUnknown.crc.html","deprecated":false},{"id":"namespace_pngchunkunknown","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"pngChunkUnknown","file":".","doc":"Creates a coder for unknown/generic PNG chunks.This coder handles the basic PNG chunk structure without any type-specific refinement. It encodes/decodes the length, type, data, and CRC fields.","url":"././~/pngChunkUnknown.html","deprecated":false},{"id":"namespace_pngfilechunks","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"pngFileChunks","file":".","doc":"Creates a coder for PNG files with a custom chunk coder.This function allows you to specify how individual chunks should be encoded/decoded, enabling custom chunk handling or type-specific refinement.","url":"././~/pngFileChunks.html","deprecated":false},{"id":"namespace_pngchunkrefined","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"pngChunkRefined","file":".","doc":"Creates a coder for PNG chunks with type-specific refinement.This coder automatically detects the chunk type and applies the appropriate refiner, transforming raw chunk data into structured objects for known chunk types (IHDR, PLTE, tRNS, bKGD, IDAT, IEND). Unknown chunk types are passed through as PngChunkUnknown.","url":"././~/pngChunkRefined.html","deprecated":false},{"id":"namespace_pngfile","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"pngFile","file":".","doc":"Creates a coder for complete PNG files with automatic chunk refinement.This is the main entry point for working with PNG files. It creates a coder that handles the PNG signature and automatically refines known chunk types (IHDR, PLTE, tRNS, bKGD, IDAT, IEND) to their structured representations.","url":"././~/pngFile.html","deprecated":false},{"id":"namespace_chunkcrc","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"chunkCrc","file":".","doc":"Calculates the CRC32 checksum for PNG chunk data.This function can accept either raw bytes or a chunk object containing type and data fields. When given a chunk object, it concatenates the type and data fields before calculating the CRC.","url":"././~/chunkCrc.html","deprecated":false}]};
})()